@* Vertical sidebar navigation for settings sections *@

<nav class="nav nav-pills flex-column settings-sidebar">
    @foreach (var section in Sections)
    {
        <button class="nav-link text-start @(section == ActiveSection ? "active" : "")"
                @onclick="() => OnSectionSelected.InvokeAsync(section)">
            <span class="me-2">@GetIcon(section)</span>@section
        </button>
    }
</nav>

@code {
    [Parameter, EditorRequired] public string ActiveSection { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnSectionSelected { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@using sv_05ee88dece0140078f8fd0fa21325510.Models

<div class="card-body">
    <div class="mb-3">
        <label class="form-label fw-semibold">Current Password</label>
        <input type="password" class="form-control" @bind="CurrentPassword" />
    </div>
    <div class="mb-3">
        <label class="form-label fw-semibold">New Password</label>
        <input type="password" class="form-control" @bind="NewPassword" />
    </div>
    <div class="mb-3">
        <label class="form-label fw-semibold">Confirm New Password</label>
        <input type="password" class="form-control" @bind="ConfirmPassword" />
    </div>

    @if (!string.IsNullOrEmpty(_errorMessage))
    {
        <div class="alert alert-danger py-2">@_errorMessage</div>
    }
    @if (_success)
    {
        <div class="alert alert-success py-2">Password updated successfully.</div>
    }

    <button class="btn btn-primary" @onclick="HandleUpdatePassword" disabled="@_saving">
        @(_saving ? "Updating…" : "Update Password")
    </button>
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<(string current, string newPw)> OnChangePassword { get; set; }

    private string CurrentPassword { get; set; } = "";
    private string NewPassword { get; set; } = "";
    private string ConfirmPassword { get; set; } = "";
    private string? _errorMessage;
    private bool _success;
    private bool _saving;

    private async Task HandleUpdatePassword()
    {
        _errorMessage = null;
        _success = false;

        if (string.IsNullOrWhiteSpace(CurrentPassword) ||
            string.IsNullOrWhiteSpace(NewPassword))
        {
            _errorMessage = "All password fields are required.";
            return;
        }
        if (NewPassword != ConfirmPassword)
        {
            _errorMessage = "New password and confirmation do not match.";
            return;
        }

        _saving = true;
        try
        {
            await OnChangePassword.InvokeAsync((CurrentPassword, NewPassword));
            _success = true;
            CurrentPassword = "";
            NewPassword = "";
            ConfirmPassword = "";
        }
        catch (Exception ex)
        {
            _errorMessage = ex.Message;
        }
        finally
        {
            _saving = false;
        }
    }
}

@using sv_05ee88dece0140078f8fd0fa21325510.Models

<table class="table table-hover align-middle mb-0">
    <thead>
        <tr>
            <th>Device</th>
            <th>Location</th>
            <th>Last Active</th>
            <th></th>
        </tr>
    </thead>
    <tbody>
        @foreach (var session in Sessions)
        {
            <tr>
                <td>@session.Device</td>
                <td>@session.Location</td>
                <td>@FormatLastActive(session.LastActive)</td>
                <td class="text-end">
                    @if (session.Id == CurrentSessionId)
                    {
                        <span class="badge bg-success">Current</span>
                    }
                    else
                    {
                        <button class="btn btn-outline-danger btn-sm"
                                @onclick="() => RequestRevoke(session)">
                            Revoke
                        </button>
                    }
                </td>
            </tr>
        }
    </tbody>
</table>

@* Confirmation dialog *@
@if (_sessionToRevoke is not null)
{
    <div class="modal fade show d-block" tabindex="-1" style="background-color: rgba(0,0,0,0.5);">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                </div>
                <div class="modal-body">
                    <p>
                        Are you sure you want to revoke the session on
                        <strong>@_sessionToRevoke.Device</strong> in
                        <strong>@_sessionToRevoke.Location</strong>?
                    </p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                    <button class="btn btn-danger" @onclick="ConfirmRevoke">Revoke</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string? CurrentSessionId { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> OnRevoke { get; set; }

    private ActiveSession? _sessionToRevoke;

    private void RequestRevoke(ActiveSession session)
        => _sessionToRevoke = session;

    private void CancelRevoke()
        => _sessionToRevoke = null;

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is not null)
        {
            await OnRevoke.InvokeAsync(_sessionToRevoke.Id);
            _sessionToRevoke = null;
        }
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

