@using sv_05ee88dece0140078f8fd0fa21325510.Models
@using sv_05ee88dece0140078f8fd0fa21325510.Services

<h4 class="mb-4">Profile</h4>

@if (_loading)
{
    <p class="text-muted">Loading profile…</p>
}
else
{
    <div class="row">
        <div class="col-md-8">
            <div class="mb-3">
                <label class="form-label fw-semibold">Display Name</label>
                <input type="text" class="form-control" @bind="_displayName" />
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">Email</label>
                <input type="email" class="form-control" @bind="_email" />
            </div>
            <div class="mb-3">
                <label class="form-label fw-semibold">Bio</label>
                <textarea class="form-control" rows="4" @bind="_bio"></textarea>
            </div>
        </div>
        <div class="col-md-4 text-center">
            <div class="mb-2">
                <img src="@_avatarUrl"
                     alt="Avatar"
                     class="rounded-circle border"
                     style="width: 120px; height: 120px; object-fit: cover;" />
            </div>
            <small class="text-muted text-break">@_avatarUrl</small>
        </div>
    </div>

    @if (!string.IsNullOrEmpty(_statusMessage))
    {
        <div class="alert @(_isError ? "alert-danger" : "alert-success") py-2 mt-2">
            @_statusMessage
        </div>
    }

    <div class="mt-3 d-flex gap-2">
        <button class="btn btn-primary" @onclick="SaveChanges" disabled="@_saving">
            @(_saving ? "Saving…" : "Save Changes")
        </button>
        <button class="btn btn-outline-secondary" @onclick="DiscardChanges">
            Discard Changes
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;

    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private UserProfile? _savedProfile;

    private bool _loading = true;
    private bool _saving;
    private string? _statusMessage;
    private bool _isError;

    protected override async Task OnInitializedAsync()
    {
        _savedProfile = await SettingsService.GetProfileAsync();
        ApplyProfile(_savedProfile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveChanges()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(updated);
            _savedProfile = updated;
            _statusMessage = "Profile saved successfully.";
            _isError = false;
        }
        catch (Exception ex)
        {
            _statusMessage = $"Error saving profile: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void DiscardChanges()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
            _statusMessage = null;
        }
    }
}

@using sv_05ee88dece0140078f8fd0fa21325510.Models
@using sv_05ee88dece0140078f8fd0fa21325510.Services

<h4 class="mb-4">Notifications</h4>

@if (_loading)
{
    <p class="text-muted">Loading notification preferences…</p>
}
else
{
    <div class="mb-4">
        <h6 class="text-muted mb-3">General</h6>

        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="emailNotif"
                   checked="@_emailNotifications"
                   @onchange="e => _emailNotifications = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>

        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="pushNotif"
                   checked="@_pushNotifications"
                   @onchange="e => _pushNotifications = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>

        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="weeklyDigest"
                   checked="@_weeklyDigest"
                   @onchange="e => _weeklyDigest = (bool)(e.Value ?? false)" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <div class="mb-4">
        <h6 class="text-muted mb-3">Muted Channels</h6>
        @foreach (var channel in _availableChannels)
        {
            var isMuted = _mutedChannels.Contains(channel);
            <div class="form-check mb-2">
                <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                       checked="@isMuted"
                       @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                <label class="form-check-label" for="@($"ch-{channel}")">
                    #@channel @(isMuted ? "(muted)" : "")
                </label>
            </div>
        }
    </div>

    @if (!string.IsNullOrEmpty(_statusMessage))
    {
        <div class="alert alert-success py-2">@_statusMessage</div>
    }

    <button class="btn btn-primary" @onclick="SavePreferences" disabled="@_saving">
        @(_saving ? "Saving…" : "Save Preferences")
    </button>
}

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private readonly List<string> _availableChannels = MockSettingsService.AvailableChannels;

    private bool _loading = true;
    private bool _saving;
    private string? _statusMessage;

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = [.. prefs.MutedChannels];
        _loading = false;
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SavePreferences()
    {
        _saving = true;
        _statusMessage = null;
        var prefs = new NotificationPrefs(
            _emailNotifications,
            _pushNotifications,
            _weeklyDigest,
            [.. _mutedChannels]);
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _statusMessage = "Notification preferences saved.";
        _saving = false;
    }
}

@using sv_05ee88dece0140078f8fd0fa21325510.Models
@using sv_05ee88dece0140078f8fd0fa21325510.Services

<h4 class="mb-4">Security</h4>

@if (_loading)
{
    <p class="text-muted">Loading security settings…</p>
}
else
{
    @* Change Password expandable panel *@
    <div class="card mb-4">
        <div class="card-header d-flex justify-content-between align-items-center"
             style="cursor: pointer;"
             @onclick="() => _passwordExpanded = !_passwordExpanded">
            <span class="fw-semibold">Change Password</span>
            <span>@(_passwordExpanded ? "▲" : "▼")</span>
        </div>
        @if (_passwordExpanded)
        {
            <ChangePasswordPanel OnChangePassword="HandleChangePassword" />
        }
    </div>

    @* Two-Factor Authentication *@
    <div class="card mb-4">
        <div class="card-body d-flex justify-content-between align-items-center">
            <div>
                <h6 class="mb-1">Two-Factor Authentication</h6>
                <small class="text-muted">
                    @if (_twoFactorEnabled)
                    {
                        <span class="text-success">● Enabled</span>
                    }
                    else
                    {
                        <span class="text-danger">● Disabled</span>
                    }
                </small>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox"
                       checked="@_twoFactorEnabled"
                       @onchange="e => _twoFactorEnabled = (bool)(e.Value ?? false)" />
            </div>
        </div>
    </div>

    @* Last Password Change *@
    @if (_lastPasswordChange.HasValue)
    {
        <p class="text-muted small mb-4">
            Last password change: @_lastPasswordChange.Value.ToString("MMMM dd, yyyy")
        </p>
    }

    @* Active Sessions *@
    <div class="card">
        <div class="card-header fw-semibold">Active Sessions</div>
        <ActiveSessionsTable Sessions="_sessions"
                             CurrentSessionId="@_sessions.FirstOrDefault()?.Id"
                             OnRevoke="HandleRevokeSession" />
    </div>
}

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;

    private bool _loading = true;
    private bool _passwordExpanded;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = [];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = [.. settings.Sessions];
        _loading = false;
    }

    private async Task HandleChangePassword((string current, string newPw) args)
    {
        await SettingsService.ChangePasswordAsync(args.current, args.newPw);
        _lastPasswordChange = DateTime.UtcNow;
    }

    private async Task HandleRevokeSession(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _sessions = _sessions.Where(s => s.Id != sessionId).ToList();
    }
}

@using sv_05ee88dece0140078f8fd0fa21325510.Models
@using sv_05ee88dece0140078f8fd0fa21325510.Services

<h4 class="mb-4">Appearance</h4>

@if (_loading)
{
    <p class="text-muted">Loading appearance settings…</p>
}
else
{
    <div class="row">
        <div class="col-md-7">
