@using sv_05ee88dece0140078f8fd0fa21325510.Models
@using sv_05ee88dece0140078f8fd0fa21325510.Services

<h4 class="mb-4">Appearance</h4>

@if (_loading)
{
    <p class="text-muted">Loading appearance settings…</p>
}
else
{
    <div class="row">
        <div class="col-md-7">
            @* Theme *@
            <div class="mb-4">
                <h6 class="text-muted mb-2">Theme</h6>
                @foreach (var theme in _themes)
                {
                    <div class="form-check form-check-inline">
                        <input class="form-check-input" type="radio" name="theme"
                               id="@($"theme-{theme}")"
                               value="@theme"
                               checked="@(_theme == theme)"
                               @onchange="() => _theme = theme" />
                        <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                    </div>
                }
            </div>

            @* Font Size *@
            <div class="mb-4">
                <h6 class="text-muted mb-2">Font Size</h6>
                @foreach (var size in _fontSizes)
                {
                    <div class="form-check form-check-inline">
                        <input class="form-check-input" type="radio" name="fontSize"
                               id="@($"fs-{size}")"
                               value="@size"
                               checked="@(_fontSize == size)"
                               @onchange="() => _fontSize = size" />
                        <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                    </div>
                }
            </div>

            @* Language *@
            <div class="mb-4">
                <h6 class="text-muted mb-2">Language</h6>
                <select class="form-select" style="max-width: 250px;"
                        @bind="_language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            @* Compact Mode *@
            <div class="mb-4">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode"
                           checked="@_compactMode"
                           @onchange="e => _compactMode = (bool)(e.Value ?? false)" />
                    <label class="form-check-label" for="compactMode">Compact Mode</label>
                </div>
            </div>

            @if (!string.IsNullOrEmpty(_statusMessage))
            {
                <div class="alert alert-success py-2">@_statusMessage</div>
            }

            <button class="btn btn-primary" @onclick="Save" disabled="@_saving">
                @(_saving ? "Saving…" : "Save")
            </button>
        </div>

        @* Live Preview *@
        <div class="col-md-5">
            <h6 class="text-muted mb-2">Preview</h6>
            <div class="border rounded p-3 @PreviewBgClass" style="@PreviewStyle">
                <h6 style="@PreviewFontStyle">Settings Dashboard</h6>
                <p class="mb-2" style="@PreviewFontStyle">
                    This is a preview of your selected appearance settings.
                </p>
                <div class="@PreviewPaddingClass">
                    <span class="badge @PreviewBadgeClass me-1">@_theme</span>
                    <span class="badge bg-secondary me-1">@_fontSize</span>
                    <span class="badge bg-info">@_language</span>
                </div>
                @if (_compactMode)
                {
                    <small class="text-muted d-block mt-2">Compact mode is on — reduced spacing.</small>
                }
            </div>
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private bool _loading = true;
    private bool _saving;
    private string? _statusMessage;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
