@page "/settings"
@using sv_05ee88dece0140078f8fd0fa21325510.Services
@rendermode InteractiveServer
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="container-fluid py-4">
    <h2 class="mb-4">⚙️ Settings</h2>
    <div class="row">
        <div class="col-md-3 col-lg-2 mb-3">
            <SettingsSidebar ActiveSection="@_activeSection"
                             OnSectionSelected="section => _activeSection = section" />
        </div>
        <div class="col-md-9 col-lg-10">
            <div class="card">
                <div class="card-body">
                    @switch (_activeSection)
                    {
                        case "Profile":
                            <ProfileSection SettingsService="SettingsService" />
                            break;
                        case "Notifications":
                            <NotificationsSection SettingsService="SettingsService" />
                            break;
                        case "Security":
                            <SecuritySection SettingsService="SettingsService" />
                            break;
                        case "Appearance":
                            <AppearanceSection SettingsService="SettingsService" />
                            break;
                    }
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    private string _activeSection = "Profile";
}

::deep .settings-sidebar .nav-link {
    color: #495057;
    border-radius: 0.375rem;
    margin-bottom: 0.25rem;
    transition: background-color 0.15s;
}

::deep .settings-sidebar .nav-link:hover {
    background-color: #e9ecef;
}

::deep .settings-sidebar .nav-link.active {
    background-color: #0d6efd;
    color: #fff;
}

